import{_ as r,o as t,c as d,j as e,a as p,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const E=JSON.parse('{"title":"E.G.O.他人之锁","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/E.G.O.他人之锁.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/E.G.O.他人之锁.md"}'),n={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/E.G.O.他人之锁.md"};function s(_,a,l,i,b,c){return t(),d("div",null,[...a[0]||(a[0]=[e("h1",{id:"e-g-o-他人之锁",tabindex:"-1"},[p("E.G.O.他人之锁 "),e("a",{class:"header-anchor",href:"#e-g-o-他人之锁","aria-label":'Permalink to "E.G.O.他人之锁"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="e-g-o-他人之锁-1" tabindex="-1">E.G.O.他人之锁 <a class="header-anchor" href="#e-g-o-他人之锁-1" aria-label="Permalink to &quot;E.G.O.他人之锁&quot;">​</a></h1><p>E.G.O.他人之锁<br> ZAYIN级<br> D+500<br> “如此诸多不断紧缠……”<br> 解析等级I：<br> 当你进行一种你已有的肉搏标准动作攻击时，你可以消耗1点意志，这次攻击将附带E.G.O.他人之锁。<br> 仅这一次攻击期间，你的双手双脚将被银色的锁链两两缠绕在一起，攻击命中时，锁链将飞射而出缠绕敌人，目标需以强韧豁免攻击出目，若豁免失败，其直到你的下个行动回合开始前视为承受D级附身来源的困难地形，并且承受10dp攻击减值，移速降低10米，若其拥有飞行能力，则飞行机动性下降一级（至多降低为无）。<br> 在该技艺生效后，你自身直到自己的下一个行动回合结束前的攻击检定降低20dp，移动速度降低30米，若在计算移速降低时，自身移速归零仍然有降低数额未满足，则按照每10米2dp攻击减值（不足10米按10米计算）的比例扣除攻击dp。<br> 若同时命中多个目标，择一生效，下不赘述。<br> 特殊的，在购买该ego后你可以在非战斗场景中随时展现出缠绕着四肢的银色锁链，并最多将其延伸出一米的长度，没有伤害能力，但具有一定的物理性质。</p><p>解析等级II：支付D+500升级，差升为C级技艺，获得2点自由属性点，此时的效果更改为：进行肉搏攻击时，消耗2点意志附带E.G.O.他人之锁，目标需以强韧豁免攻击出目，若豁免失败，其直到你的下个行动回合开始前视为承受C级附身来源的困难地形；同时减少2点AP，这是C级附身来源的耗竭效果；并承受20dp攻击减值，若其拥有飞行能力，则飞行机动性下降两级（至多降低为无）。<br> 在该技艺生效后，你自身直到自己的下一个行动回合结束前承受40dp攻击减值，移动速度降低60米，若在计算移速降低时，自身移速归零仍然有降低数额未满足，则按照每10米2dp攻击减值（不足10米按10米计算）的比例扣除攻击dp。</p><p>解析等级III：在购买【解析等级II】后，支付10xp研发，如同兑换技艺般获得2点自由属性点，在原有效果的基础上，额外令目标的攻击检定承受C级附身来源的【劣化1】并对其造成8dp攻击减值。<br> 同时额外令自身的攻击检定承受【劣化2】与8dp攻击减值。</p><p>解析等级VI：在购买【解析等级III】后支付D+500升级，差升为B级技艺，获得2点自由属性点，此时的效果更改为：进行肉搏攻击时，消耗3点意志附带E.G.O.他人之锁，目标需以强韧豁免攻击出目，若豁免失败，其直到你的下个行动回合开始前视为承受B级附身来源的困难地形，因肉体上无形的锁链而承受减少4点AP，这是B级附身来源的耗竭效果，因精神上无处不在的枷锁而承受B级附身来源的迟滞效果；目标将承受20dp攻击减值并在攻击检定上承受B级附身来源的【劣化2】，若其拥有飞行能力，则飞行机动性下降四级（至多降低为无）。<br> 在该技艺生效后，你自身直到自己的下一个行动回合结束前承受60dp攻击减值并在攻击检定上承受【劣化3】，移动速度降低140米，若在计算移速降低时，自身移速归零仍然有降低数额未满足，则按照每10米1dp攻击减值（不足10米按10米计算）的比例扣除攻击dp。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const I=r(n,[["render",s]]);export{E as __pageData,I as default};
